package travelcare_agent.evaluation.scoring; import org.springframework.stereotype.Component; import com.fasterxml.jackson.databind.JsonNode; import java.util.*; @Component public class OutputAssertionScorer implements EvaluationScorer {public String name(){return "outputAssertions";} public ScoreResult score(EvaluationScoringContext c){JsonNode e=c.expectation();boolean configured=e!=null&&(e.has("outputContains")||e.has("outputNotContains")||e.has("outputEquals"));if(!configured)return ScoreResult.skipped(name());String out=Objects.toString(c.output(),"");List<String> failures=new ArrayList<>();if(e.has("outputContains"))e.get("outputContains").forEach(x->{if(!out.contains(x.asText()))failures.add("missing: "+x.asText());});if(e.has("outputNotContains"))e.get("outputNotContains").forEach(x->{if(out.contains(x.asText()))failures.add("forbidden: "+x.asText());});if(e.has("outputEquals")&&!out.equals(e.get("outputEquals").asText()))failures.add("not equal");return ScoreResult.of(name(),failures.isEmpty(),e,out,failures.isEmpty()?"output assertions matched":String.join(", ",failures));}}
